// src/pages/RegisterManageSub2Page.js (Tên component bạn có thể đổi thành FarmListPage cho rõ ràng)
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import '../Dashboard.css'; // Đảm bảo bạn đã có file Dashboard.css
import './FormPage.css'; // Nếu bạn có các style form riêng

function FarmListPage() { // Đổi tên component này nếu bạn muốn, ví dụ: FarmListPage
  const [farms, setFarms] = useState([]);
  const [filter, setFilter] = useState('');
  const navigate = useNavigate();
  const token = localStorage.getItem('token'); // Lấy token để xác thực API

  // Hàm tải danh sách cơ sở nuôi
  useEffect(() => {
    const fetchFarms = async () => {
      try {
        const response = await axios.get('http://localhost:10000/api/farms', {
          headers: {
            Authorization: `Bearer ${token}` // Thêm token vào header
          }
        });
        setFarms(response.data);
      } catch (error) {
        console.error('❌ Lỗi khi lấy danh sách cơ sở nuôi:', error);
        alert('Không thể tải danh sách cơ sở nuôi. Vui lòng thử lại hoặc kiểm tra quyền truy cập.');
        // Nếu lỗi 401/403, có thể chuyển hướng về trang đăng nhập
        if (error.response && (error.response.status === 401 || error.response.status === 403)) {
          navigate('/');
        }
      }
    };

    if (token) { // Chỉ fetch khi có token
      fetchFarms();
    } else {
      // Nếu không có token, chuyển hướng về trang đăng nhập
      navigate('/');
    }
  }, [token, navigate]); // Thêm token và navigate vào dependency array

  // Xử lý xoá cơ sở nuôi
  const handleDelete = async (id) => {
    if (window.confirm('Bạn có chắc chắn muốn xoá cơ sở nuôi này không?')) {
      try {
        await axios.delete(`http://localhost:10000/api/farms/${id}`, {
          headers: {
            Authorization: `Bearer ${token}`
          }
        });
        setFarms(farms.filter(f => f._id !== id));
        alert('Xoá cơ sở nuôi thành công!');
      } catch (error) {
        console.error('❌ Lỗi khi xoá cơ sở nuôi:', error);
        alert('Xoá thất bại. Vui lòng thử lại.');
      }
    }
  };

  // Xử lý sửa cơ sở nuôi (chuyển hướng đến trang chỉnh sửa)
  const handleEdit = (id) => {
    navigate(`/edit-farm/${id}`); // Chuyển hướng đến trang chỉnh sửa FarmEditPage
  };

  // Xử lý xem chi tiết cơ sở nuôi
  const handleView = (id) => {
    navigate(`/farm-details/${id}`); // Chuyển hướng đến trang chi tiết FarmDetail
  };

  // Lọc danh sách cơ sở nuôi theo tên cơ sở, tỉnh, hoặc chủ trại
  const filteredFarms = farms.filter(f =>
    (f.tenCoSo || '').toLowerCase().includes(filter.toLowerCase()) ||
    (f.tinh || '').toLowerCase().includes(filter.toLowerCase()) ||
    (f.chuTrai || '').toLowerCase().includes(filter.toLowerCase())
  );

  return (
    <div style={{ padding: 20 }}>
      <h2>📋 Danh sách cơ sở nuôi</h2>

      <input
        type="text"
        placeholder="🔍 Tìm kiếm theo tên cơ sở, tỉnh hoặc chủ trại..."
        value={filter}
        onChange={e => setFilter(e.target.value)}
        style={{ marginBottom: 12, padding: 8, width: '50%' }}
      />

      {farms.length === 0 && !filter && <p>Không có cơ sở nuôi nào được đăng ký.</p>}
      {farms.length === 0 && filter && <p>Không tìm thấy cơ sở nuôi nào phù hợp với bộ lọc.</p>}

      {filteredFarms.length > 0 && (
        <table border="1" cellPadding="8" style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead style={{ background: '#f0f0f0' }}>
            <tr>
              <th>Tên cơ sở</th>
              <th>Tỉnh</th>
              <th>Huyện</th>
              <th>Xã</th>
              <th>Chủ trại</th>
              <th>SĐT</th>
              <th>🛠️</th>
            </tr>
          </thead>
          <tbody>
            {filteredFarms.map((f, i) => (
              <tr key={f._id || i}> {/* Sử dụng f._id làm key nếu có, hoặc i nếu không */}
                <td>{f.tenCoSo}</td>
                <td>{f.tinh}</td>
                <td>{f.huyen}</td>
                <td>{f.xa}</td>
                <td>{f.chuTrai}</td>
                <td>{f.soDienThoai}</td>
                <td>
                  <button onClick={() => handleView(f._id)}>👁️</button>{' '}
                  <button onClick={() => handleEdit(f._id)}>✏️</button>{' '}
                  <button onClick={() => handleDelete(f._id)}>🗑️</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

export default FarmListPage;
